        {
        die "Usage: lef_layer_tf_number_map.pl Tech_file_name.tf Lef_file_name.lef\n";
        }
        else
                {
                $tech_file = $ARGV[0];
                $lef_file = $ARGV[1];
		$tmp_s1 = $ARGV[0];
