		$tmp_s2 = $ARGV[1];
		$tmp_s2 =~ s/\.lef/_lef/;
                $lef_tf_map_file = $tmp_s2."_".$tmp_s1.".map";
                $lef_tf_log_file = $tmp_s2."_".$tmp_s1.".log";
