$processing_tf_layer = 0;
$found_maskName = 0;
$tf_masks = 0;
while ($line = <tech_file>) 
{
	chop $line;
	if ( $line =~ /^[lL][aA][yY][eE][rR][\s]+\"([\w\W]+)\"[\s]+\{.*$/ )
	{
	if ($processing_tf_layer ==0)
		{
		$processing_tf_layer = 1;
		$tf_layer_name = $1;
		print_log( "\nBeginning to process $tf_layer_name layer...\n");
